def gen(rng, size):
    n = max(2, min(size, 100))
    edges = []
    for i in range(n):
        for j in range(i + 1, n):
            if rng.random() < 0.4:
                edges.append([i, j, rng.randint(1, 10000)])
    if not edges:
        edges.append([0, 1, rng.randint(1, 10000)])
    threshold = rng.randint(1, 10000)
    return [n, edges, threshold]

